)

foreach ($file in $files) {
    if (Test-Path $file) {
        Write-Host "`n=== Checking: $file ===" -ForegroundColor Cyan

        # Get file size
        $sizeMB = [math]::Round((Get-Item $file).Length / 1MB, 2)
        Write-Host "Size: $($sizeMB) MB" -ForegroundColor Gray

        # Check if it's a binary file (Bitcoin Core wallets are binary)
        try {
            $firstBytes = Get-Content -Path $file -Encoding Byte -TotalCount 32 -ErrorAction SilentlyContinue
            Write-Host "Binary header check: PASSED" -ForegroundColor Green

            # Bitcoin Core HD wallets typically have Berkeley DB signatures
            if ($sizeMB -ge 50) {
                Write-Host "VERDICT: Likely Bitcoin Core HD wallet (standard size)" -ForegroundColor Yellow
            } elseif ($sizeMB -lt 10) {
                Write-Host "VERDICT: Too small for modern HD wallet" -ForegroundColor Red
            } else {
                Write-Host "VERDICT: Intermediate size, verify further" -ForegroundColor Orange
            }
        } catch {
            Write-Host "Binary read failed (expected for encrypted wallets)" -ForegroundColor Yellow
